const display = document.getElementById('display');
let memory = 0;

function calculate(expression) {
    try {
        // Replace power operator ^ with Math.pow
        expression = expression.replace(/\^/g, '**');
        // Replace functions with Math equivalents
        expression = expression.replace(/sin/g, 'Math.sin');
        expression = expression.replace(/cos/g, 'Math.cos');
        expression = expression.replace(/tan/g, 'Math.tan');
        expression = expression.replace(/log/g, 'Math.log10');
        expression = expression.replace(/sqrt/g, 'Math.sqrt');

        // Evaluate the expression
        let result = eval(expression);
        if (typeof result === 'number' && !isNaN(result)) {
            return result;
        } else {
            return 'Error';
        }
    } catch (e) {
        return 'Error';
    }
}

function updateDisplay(value) {
    display.value += value;
}

function clearDisplay() {
    display.value = '';
}

function memoryClear() {
    memory = 0;
}

function memoryRecall() {
    updateDisplay(memory.toString());
}

function memoryAdd() {
    let current = parseFloat(display.value);
    if (!isNaN(current)) {
        memory += current;
    }
}

function handleButtonClick(e) {
    const action = e.target.getAttribute('data-action');
    if (!action) return;

    switch(action) {
        case 'clear':
            clearDisplay();
            break;
        case 'memory-clear':
            memoryClear();
            break;
        case 'memory-recall':
            memoryRecall();
            break;
        case 'memory-add':
            memoryAdd();
            break;
        case 'equals':
            display.value = calculate(display.value);
            break;
        case 'sin':
        case 'cos':
        case 'tan':
        case 'log':
        case 'sqrt':
            updateDisplay(action + '(');
            break;
        case 'power':
            updateDisplay('^');
            break;
        case 'add':
            updateDisplay('+');
            break;
        case 'subtract':
            updateDisplay('-');
            break;
        case 'multiply':
            updateDisplay('*');
            break;
        case 'divide':
            updateDisplay('/');
            break;
        case 'decimal':
            updateDisplay('.');
            break;
        case 'open-paren':
            updateDisplay('(');
            break;
        case 'close-paren':
            updateDisplay(')');
            break;
        default:
            if (!isNaN(action)) {
                updateDisplay(action);
            }
            break;
    }
}

function handleKeyboardInput(e) {
    const allowedKeys = '0123456789+-*/().';
    if (allowedKeys.includes(e.key)) {
        updateDisplay(e.key);
    } else if (e.key === 'Enter') {
        display.value = calculate(display.value);
    } else if (e.key === 'Backspace') {
        display.value = display.value.slice(0, -1);
    }
}

document.querySelector('.buttons').addEventListener('click', handleButtonClick);
document.addEventListener('keydown', handleKeyboardInput);
